const PRICE_KEY = "amaryllis_daily_prices_v2";

export { SEED_DAILY_PRICES, PRICE_KEY };

export function loadDailyPrices() {
  try {
    const manual = JSON.parse(localStorage.getItem(PRICE_KEY) || "{}");
    const merged = {};
    for (const bid of Object.keys(SEED_DAILY_PRICES)) {
      merged[bid] = { ...SEED_DAILY_PRICES[bid], ...(manual[bid] || {}) };
    }
    return merged;
  } catch { return { ...SEED_DAILY_PRICES }; }
}

export function saveDailyPrices(data) {
  // Ne stocker que les overrides manuels (diff vs SEED)
  const overrides = {};
  for (const bid of Object.keys(SEED_DAILY_PRICES)) {
    overrides[bid] = {};
    for (const [date, price] of Object.entries(data[bid] || {})) {
      if (SEED_DAILY_PRICES[bid]?.[date] !== price) {
        overrides[bid][date] = price;
      }
    }
  }
  localStorage.setItem(PRICE_KEY, JSON.stringify(overrides));
  window.dispatchEvent(new Event("amaryllis_prices_updated"));
}
